202→// VTT解析 (处理YouTube自动字幕的双行格式)
203→function parseVTT(vtt) {
204→  const raw = [];
205→  for (const block of vtt.split(/\n\n+/)) {
206→    const lines = block.trim().split('\n');
207→    for (let i = 0; i < lines.length; i++) {
208→      const m = lines[i].match(/(\d{2}):(\d{2}):(\d{2})\.(\d{3})\s*-->\s*(\d{2}):(\d{2}):(\d{2})\.(\d{3})/);
209→      if (!m) continue;
210→      const start = +m[1]*3600 + +m[2]*60 + +m[3] + +m[4]/1000;
211→      const end = +m[5]*3600 + +m[6]*60 + +m[7] + +m[8]/1000;
212→      // 跳过极短条目(YouTube自动字幕的过渡帧)
213→      if (end - start < 0.05) break;
214→      // 取最后一行非空文本(YouTube双行字幕中新内容在最后一行)
215→      const textLines = lines.slice(i+1).map(l => l.replace(/<[^>]+>/g, '').trim()).filter(Boolean);
216→      const text = textLines.length > 0 ? textLines[textLines.length - 1] : '';
217→      if (text) raw.push({ start, end, text });
218→      break;
219→    }
220→  }
221→  // 合并连续相同文本，去重
222→  const result = [];
223→  for (const s of raw) {
224→    if (result.length > 0 && result[result.length-1].text === s.text) {
225→      result[result.length-1].end = s.end; // 延长时间
226→    } else {
227→      result.push({ ...s });
228→    }
229→  }
230→  return result;
231→}
