        --select-bg: #f1f5f9;
        --popup-bg: rgba(255,255,255,0.97);
        --word-panel-bg: linear-gradient(145deg, rgba(255,255,255,0.97), rgba(241,245,249,0.95));
        --word-card-bg: linear-gradient(135deg, rgba(99,102,241,0.08), rgba(139,92,246,0.06));
