body.font-small { --sub-font: 18px; --word-font: 22px; --trans-font: 15px; --def-font: 13px; --dict-input-font: 15px; }
body.font-medium { --sub-font: 22px; --word-font: 26px; --trans-font: 18px; --def-font: 15px; --dict-input-font: 18px; }
body.font-large { --sub-font: 28px; --word-font: 32px; --trans-font: 22px; --def-font: 18px; --dict-input-font: 22px; }
body.font-xlarge { --sub-font: 34px; --word-font: 38px; --trans-font: 26px; --def-font: 21px; --dict-input-font: 26px; }

body {
    font-family: 'Microsoft YaHei UI', -apple-system, sans-serif;
    min-height: 100vh;
    background: var(--bg);
    overflow-y: auto;
    color: var(--text);
}

.aurora-bg {
    position: fixed; top: 0; left: 0; width: 100%; height: 100%; z-index: -1;
    background: var(--bg-gradient);
}
.aurora-blob {
    position: absolute; border-radius: 50%; filter: blur(80px); opacity: var(--blob-opacity);
    animation: float 20s ease-in-out infinite;
}
.blob-1 { width: 500px; height: 500px; background: var(--blob1); top: -200px; left: -100px; }
.blob-2 { width: 400px; height: 400px; background: var(--blob2); top: 50%; right: -150px; animation-delay: -5s; }
.blob-3 { width: 450px; height: 450px; background: var(--blob3); bottom: -150px; left: 30%; animation-delay: -10s; }
@keyframes float {
    0%, 100% { transform: translate(0,0) scale(1); }
    25% { transform: translate(50px,-50px) scale(1.1); }
    50% { transform: translate(-30px,30px) scale(0.9); }
    75% { transform: translate(-50px,-30px) scale(1.05); }
}

.container { display: flex; flex-direction: column; align-items: center; padding: 20px; min-height: 100vh; }
.header { text-align: center; margin-bottom: 15px; }
.title { font-size: 28px; color: var(--text); text-shadow: 0 2px 20px rgba(255,107,157,0.5); }
.subtitle { font-size: 13px; color: var(--accent); margin-top: 5px; }

.glass-card {
    background: var(--glass-bg); backdrop-filter: blur(20px);
    border: 1px solid var(--glass-border); border-radius: 16px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.3);
}

/* 控制栏 */
.control-bar { width: 100%; max-width: 900px; padding: 15px 20px; margin-bottom: 15px; }
.input-row { display: flex; gap: 8px; align-items: center; }
.url-input {
    flex: 1; padding: 10px 14px; font-size: 13px;
    background: var(--input-bg); border: 1px solid var(--input-border);
    border-radius: 10px; color: var(--text); outline: none;
}
.url-input:focus { border-color: var(--accent); box-shadow: 0 0 15px rgba(255,107,157,0.3); }
.url-input::placeholder { color: var(--text-dim2); }

.paste-btn {
    width: 40px; height: 40px; font-size: 18px;
    background: var(--btn-secondary);
    border: none; border-radius: 10px; cursor: pointer; color: var(--text);
}
.paste-btn:hover { transform: scale(1.05); }

.lang-select {
    padding: 10px; font-size: 13px; background: var(--input-bg);
    border: 1px solid var(--input-border); border-radius: 10px;
    color: var(--text); outline: none; cursor: pointer;
}
.lang-select option { background: var(--select-bg); color: var(--text); }
.video-select { flex: 1; min-width: 200px; }

.label { font-size: 12px; color: var(--accent); font-weight: bold; margin-right: 8px; white-space: nowrap; }

.progress-row { display: flex; align-items: center; gap: 10px; margin-top: 10px; }
.progress-bar { flex: 1; height: 8px; background: var(--input-bg); border-radius: 8px; overflow: hidden; }
.progress-fill { height: 100%; width: 0%; background: linear-gradient(90deg, var(--accent), var(--accent2), var(--accent3)); border-radius: 8px; transition: width 0.3s; }
.status-text { font-size: 12px; color: var(--text-dim); white-space: nowrap; }

.video-list-row { display: flex; align-items: center; margin-top: 10px; gap: 8px; }

/* 按钮 */
.btn {
    padding: 10px 20px; font-size: 14px; font-weight: bold; color: #fff;
    border: none; border-radius: 10px; cursor: pointer; transition: all 0.3s;
}
.btn-primary { background: var(--btn-primary); }
.btn-primary:hover { transform: translateY(-2px); box-shadow: 0 4px 20px rgba(255,51,102,0.5); }
.btn-small { padding: 8px 14px; font-size: 13px; background: var(--btn-secondary); border-radius: 8px; }
.btn-small:hover { transform: translateY(-1px); }
.btn:disabled { opacity: 0.5; cursor: not-allowed; }

/* 播放区 */
.player-area { width: 100%; max-width: 900px; padding: 15px; }
video { width: 100%; border-radius: 10px; background: #000; max-height: 450px; }

/* 模式切换 */
.mode-bar { display: flex; gap: 8px; margin: 12px 0; }
.mode-btn {
    flex: 1; padding: 10px; font-size: 13px; color: var(--text); text-align: center;
    background: rgba(255,255,255,0.05); border: 1px solid var(--glass-border);
    border-radius: 10px; cursor: pointer; transition: all 0.3s;
}
.mode-btn:hover { background: rgba(255,255,255,0.1); }
.mode-btn.active { background: linear-gradient(135deg, rgba(255,107,157,0.3), rgba(138,43,226,0.3)); border-color: var(--accent); }

/* 字幕区 */
.subtitle-area {
    min-height: 80px; padding: 15px; background: var(--sub-bg);
    border-radius: 12px; text-align: center;
}
.subtitle-text { font-size: var(--sub-font); color: var(--text); line-height: 2; }
.subtitle-text .word {
    cursor: pointer; padding: 2px 1px; border-radius: 4px; transition: background 0.2s;
    display: inline-block;
}
.subtitle-text .word:hover { background: var(--sub-hover); }

/* 字幕滚动列表 */
.subtitle-list {
    max-height: 200px; overflow-y: auto; margin-top: 10px; padding: 8px;
    background: var(--sub-bg); border-radius: 10px;
}
.sub-list-item {
    display: flex; gap: 10px; padding: 6px 10px; border-radius: 6px;
    cursor: pointer; transition: background 0.2s; font-size: 13px;
}
.sub-list-item:hover { background: rgba(255,255,255,0.08); }
.sub-list-item.active { background: var(--sub-active-bg); border-left: 3px solid var(--sub-active-border); }
.sub-time { color: var(--text-dim2); white-space: nowrap; min-width: 40px; }
.sub-content { color: var(--text-dim); }
.sub-list-item.active .sub-content { color: var(--text); }

/* 听写区 */
.dictation-area { padding: 15px; background: rgba(26,10,42,0.6); border-radius: 12px; }
.dictation-sentence { display: flex; flex-wrap: wrap; gap: 6px; justify-content: center; margin-bottom: 12px; }
.dictation-sentence input {
    width: 80px; padding: 8px 10px; font-size: var(--dict-input-font); text-align: center;
    background: rgba(255,255,255,0.08); border: 1px solid rgba(255,255,255,0.2);
    border-radius: 6px; color: #fff; outline: none;
}
.dictation-sentence input:focus { border-color: #00c8ff; box-shadow: 0 0 10px rgba(0,200,255,0.3); }
.dictation-sentence input.correct { border-color: #4ade80; background: rgba(74,222,128,0.15); }
.dictation-sentence input.wrong { border-color: #f87171; background: rgba(248,113,113,0.15); }
.dictation-sentence .answer-hint { font-size: 11px; color: #f87171; text-align: center; margin-top: 2px; }
.dict-word-group { display: flex; flex-direction: column; align-items: center; }
.dict-word-group .word-clickable {
    font-size: 11px; color: rgba(255,255,255,0.4); cursor: pointer; margin-top: 2px;
}
.dict-word-group .word-clickable:hover { color: #ff6b9d; }
.dictation-controls { display: flex; gap: 8px; justify-content: center; }

/* 音形义例句内联面板 - 精美卡片式 */
.word-inline-panel {
    margin-top: 14px; padding: 0; text-align: left;
    background: linear-gradient(145deg, rgba(30,12,50,0.95), rgba(50,25,80,0.9));
    border: 1px solid rgba(255,107,157,0.35); border-radius: 16px;
    animation: fadeIn 0.3s ease-out;
    box-shadow: 0 6px 30px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.06);
    overflow: hidden;
}
@keyframes fadeIn { from { opacity: 0; transform: translateY(-8px); } to { opacity: 1; transform: translateY(0); } }

.word-card {
    display: flex; align-items: center; gap: 16px; padding: 18px 22px;
    background: linear-gradient(135deg, rgba(255,107,157,0.12), rgba(138,43,226,0.1));
    border-bottom: 1px solid rgba(255,255,255,0.06);
}
.word-card-left { display: flex; flex-direction: column; gap: 4px; min-width: 120px; }
.word-card-word { font-size: var(--word-font); font-weight: 800; color: #ff6b9d; letter-spacing: 0.5px; text-shadow: 0 1px 8px rgba(255,107,157,0.3); }
.word-card-phonetic { font-size: var(--def-font); color: rgba(255,255,255,0.55); font-style: italic; }
.word-card-speak {
    margin-top: 6px; padding: 6px 14px; font-size: 13px; color: #fff; width: fit-content;
    background: linear-gradient(135deg, rgba(6,182,212,0.4), rgba(138,43,226,0.4));
    border: 1px solid rgba(6,182,212,0.3); border-radius: 20px; cursor: pointer;
    transition: all 0.2s;
}
.word-card-speak:hover { transform: scale(1.05); box-shadow: 0 2px 12px rgba(6,182,212,0.4); }
.word-card-right { flex: 1; }
.word-card-trans { font-size: var(--trans-font); color: #fff; line-height: 1.7; font-weight: 500; }

.word-card-sections { padding: 14px 22px 16px; display: flex; gap: 16px; }
.word-card-section { flex: 1; }
.word-card-section-title {
    font-size: 13px; font-weight: bold; color: rgba(255,255,255,0.45);
    letter-spacing: 1px; margin-bottom: 8px;
    padding-bottom: 6px; border-bottom: 1px solid rgba(255,255,255,0.06);
}
.word-card-section-body { font-size: var(--def-font); line-height: 1.9; }
.word-card-section-body .def-item {
    margin-bottom: 6px; padding: 6px 10px; color: rgba(255,255,255,0.85);
    background: rgba(255,255,255,0.04); border-radius: 8px;
    border-left: 3px solid rgba(138,43,226,0.5);
}
.word-card-section-body .pos { color: #a78bfa; font-weight: bold; margin-right: 6px; }
.word-card-section-body .example {
    margin-bottom: 6px; padding: 6px 10px; color: rgba(255,255,255,0.7);
    background: rgba(255,107,157,0.04); border-radius: 8px;
    border-left: 3px solid rgba(255,107,157,0.4);
}

/* 语音识别状态 */
.recognition-status { font-size: 11px; color: #06b6d4; margin-top: 6px; }

/* 单词弹窗 */
.word-popup {
    position: fixed; z-index: 2000; width: 340px; max-height: 400px; overflow-y: auto;
    background: rgba(30,15,50,0.95); backdrop-filter: blur(20px);
    border: 1px solid rgba(255,107,157,0.3); border-radius: 14px;
    box-shadow: 0 10px 40px rgba(0,0,0,0.6); padding: 15px;
}
.popup-header { display: flex; align-items: center; gap: 8px; margin-bottom: 10px; }
.popup-word { font-size: 20px; font-weight: bold; color: #ff6b9d; }
.popup-phonetic { font-size: 13px; color: rgba(255,255,255,0.5); }
.popup-speak {
    font-size: 18px; background: none; border: none; cursor: pointer; padding: 2px;
}
.popup-speak:hover { transform: scale(1.2); }
.popup-close {
    margin-left: auto; width: 24px; height: 24px; font-size: 14px;
    background: rgba(255,255,255,0.1); border: none; border-radius: 50%;
    color: #fff; cursor: pointer;
}
.popup-close:hover { background: rgba(255,107,157,0.4); }
.popup-translation { font-size: 14px; color: #fff; line-height: 1.6; margin-bottom: 10px; }
.popup-examples { font-size: 12px; color: rgba(255,255,255,0.6); line-height: 1.8; }
.popup-examples .example { margin-bottom: 6px; padding-left: 10px; border-left: 2px solid rgba(255,107,157,0.3); }
.popup-examples .def-item { margin-bottom: 4px; }
.popup-examples .pos { color: #8a2be2; font-style: italic; margin-right: 4px; }

/* AI按钮 */
.btn-ai {
    padding: 6px 14px; font-size: 12px; color: #fff; margin-top: 10px;
    background: linear-gradient(135deg, #06b6d4, #8a2be2); border: none;
    border-radius: 8px; cursor: pointer; transition: all 0.3s;
}
.btn-ai:hover { transform: translateY(-1px); box-shadow: 0 4px 15px rgba(6,182,212,0.4); }
.btn-ai-small { margin-top: 8px; display: block; width: 100%; text-align: center; }

/* AI结果区 */
.ai-result, .popup-ai-result {
    margin-top: 10px; padding: 12px; font-size: 13px; color: rgba(255,255,255,0.85);
    background: rgba(6,182,212,0.1); border: 1px solid rgba(6,182,212,0.2);
    border-radius: 10px; line-height: 1.8; white-space: pre-wrap;
}

/* 弹窗(modal) */
.modal {
    display: none; position: fixed; top: 0; left: 0; width: 100%; height: 100%;
    background: rgba(0,0,0,0.7); backdrop-filter: blur(5px);
    z-index: 3000; align-items: center; justify-content: center;
}
.modal.show { display: flex; }
.modal-content { width: 90%; max-width: 450px; padding: 20px; }
.modal-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px; }
.modal-header h2 { font-size: 18px; color: #ff6b9d; }
.modal-body { color: #fff; }
.form-group { margin-bottom: 12px; }
.form-group .label { display: block; margin-bottom: 6px; }

::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar-track { background: rgba(255,255,255,0.05); border-radius: 6px; }
::-webkit-scrollbar-thumb { background: rgba(255,107,157,0.4); border-radius: 6px; }

