    --text-dim2: rgba(255,255,255,0.4);
    --btn-primary: linear-gradient(135deg, #ff3366, #ff6b9d);
    --btn-secondary: linear-gradient(135deg, #8a2be2, #5d26c1);
    --sub-bg: rgba(26,10,42,0.6);
    --sub-hover: rgba(255,107,157,0.3);
