    }
}

/* 跟随系统暗色 - 复用默认极光主题 */
@media (prefers-color-scheme: dark) {
    [data-theme="system"] {
        --bg: #0a0a1a;
        --bg-gradient: linear-gradient(135deg, #0a0a1a 0%, #1a0a2e 50%, #0a1a2e 100%);
        --glass-bg: rgba(42,26,58,0.6);
        --glass-border: rgba(255,255,255,0.1);
        --input-bg: rgba(26,10,42,0.8);
        --input-border: rgba(255,107,157,0.3);
        --accent: #ff6b9d;
        --accent2: #8a2be2;
        --accent3: #06b6d4;
        --text: #fff;
        --text-dim: rgba(255,255,255,0.6);
        --text-dim2: rgba(255,255,255,0.4);
        --btn-primary: linear-gradient(135deg, #ff3366, #ff6b9d);
        --btn-secondary: linear-gradient(135deg, #8a2be2, #5d26c1);
        --sub-bg: rgba(26,10,42,0.6);
        --sub-hover: rgba(255,107,157,0.3);
        --sub-active-bg: rgba(255,107,157,0.2);
        --sub-active-border: #ff6b9d;
        --select-bg: #1a0a2e;
        --popup-bg: rgba(30,15,50,0.95);
        --word-panel-bg: linear-gradient(145deg, rgba(30,12,50,0.95), rgba(50,25,80,0.9));
        --word-card-bg: linear-gradient(135deg, rgba(255,107,157,0.12), rgba(138,43,226,0.1));
        --ai-bg: rgba(6,182,212,0.1);
        --ai-border: rgba(6,182,212,0.2);
        --scrollbar-thumb: rgba(255,107,157,0.4);
        --blob1: linear-gradient(45deg, #ff6b9d, #c04868);
        --blob2: linear-gradient(45deg, #8a2be2, #5d26c1);
        --blob3: linear-gradient(45deg, #00c8ff, #06b6d4);
        --blob-opacity: 0.5;
