:root {
    --sub-font: 22px;
    --word-font: 26px;
    --trans-font: 18px;
    --def-font: 15px;
    --dict-input-font: 18px;
    /* 默认极光暗色主题 */
    --bg: #0a0a1a;
    --bg-gradient: linear-gradient(135deg, #0a0a1a 0%, #1a0a2e 50%, #0a1a2e 100%);
    --glass-bg: rgba(42,26,58,0.6);
    --glass-border: rgba(255,255,255,0.1);
    --input-bg: rgba(26,10,42,0.8);
    --input-border: rgba(255,107,157,0.3);
    --accent: #ff6b9d;
    --accent2: #8a2be2;
    --accent3: #06b6d4;
    --text: #fff;
    --text-dim: rgba(255,255,255,0.6);
    --text-dim2: rgba(255,255,255,0.4);
    --btn-primary: linear-gradient(135deg, #ff3366, #ff6b9d);
    --btn-secondary: linear-gradient(135deg, #8a2be2, #5d26c1);
    --sub-bg: rgba(26,10,42,0.6);
    --sub-hover: rgba(255,107,157,0.3);
    --sub-active-bg: rgba(255,107,157,0.2);
    --sub-active-border: #ff6b9d;
    --select-bg: #1a0a2e;
    --popup-bg: rgba(30,15,50,0.95);
    --word-panel-bg: linear-gradient(145deg, rgba(30,12,50,0.95), rgba(50,25,80,0.9));
    --word-card-bg: linear-gradient(135deg, rgba(255,107,157,0.12), rgba(138,43,226,0.1));
    --ai-bg: rgba(6,182,212,0.1);
    --ai-border: rgba(6,182,212,0.2);
    --scrollbar-thumb: rgba(255,107,157,0.4);
    --blob1: linear-gradient(45deg, #ff6b9d, #c04868);
    --blob2: linear-gradient(45deg, #8a2be2, #5d26c1);
    --blob3: linear-gradient(45deg, #00c8ff, #06b6d4);
    --blob-opacity: 0.5;
}

/* 宋式美学主题 */
[data-theme="song"] {
    --bg: #f5f0e8;
    --bg-gradient: linear-gradient(135deg, #f5f0e8 0%, #ebe4d4 50%, #e8e0d0 100%);
    --glass-bg: rgba(255,250,240,0.75);
    --glass-border: rgba(139,90,43,0.15);
    --input-bg: rgba(255,252,245,0.9);
    --input-border: rgba(139,90,43,0.25);
    --accent: #8b5a2b;
    --accent2: #a0522d;
    --accent3: #6b8e23;
    --text: #3e2723;
    --text-dim: rgba(62,39,35,0.65);
    --text-dim2: rgba(62,39,35,0.4);
    --btn-primary: linear-gradient(135deg, #8b5a2b, #a0522d);
    --btn-secondary: linear-gradient(135deg, #6b8e23, #556b2f);
    --sub-bg: rgba(245,235,220,0.8);
    --sub-hover: rgba(139,90,43,0.15);
    --sub-active-bg: rgba(139,90,43,0.12);
    --sub-active-border: #8b5a2b;
    --select-bg: #f0e8d8;
    --popup-bg: rgba(250,245,235,0.97);
    --word-panel-bg: linear-gradient(145deg, rgba(250,245,235,0.97), rgba(240,232,216,0.95));
    --word-card-bg: linear-gradient(135deg, rgba(139,90,43,0.08), rgba(107,142,35,0.06));
